-- Актуализация FAQ: правим неточность про категории/серверы и добавляем вопросы
-- про вложения, приватные статьи, журнал активности, статистику участника.

UPDATE faq_items
SET answer = '<p><strong>Категория</strong> показывает, к какой части проекта относится задача (например «Веб», «Лаунчер», «Клиент», «Сервер» и т.д.) — помогает быстро ориентироваться и фильтровать задачи в боковой панели.</p>
<p><strong>Сервер</strong> показывает, на каком игровом сервере должна применяться задача.</p>
<p>Если нужна новая категория или сервер, которых нет в списке — обратитесь к администратору проекта: список категорий и серверов настраивается отдельно, не через обычный интерфейс.</p>',
    updated_at = now()
WHERE question = 'Что такое категории и серверы у задачи?';

INSERT INTO faq_items (question, answer, sort_order) VALUES
('Можно ли прикрепить файл к задаче, идее или статье?', '<p>Да. При создании или редактировании задачи, идеи или статьи базы знаний есть блок «Вложения» — нажмите «Прикрепить файл» и выберите файл на компьютере.</p>
<p>Можно прикреплять документы, архивы, изображения и другие файлы — максимальный размер одного файла 300 МБ. Загруженный файл виден всем, у кого есть доступ к задаче/идее/статье; скачать его можно кликом по названию, убрать — крестиком рядом с файлом.</p>', 17),
('Как сделать статью базы знаний приватной?', '<p>При создании или редактировании статьи в блоке «Доступ» выберите «Приватная» вместо «Публичная» и укажите конкретных участников команды, которым статья будет видна.</p>
<p>Автор статьи и администраторы видят приватную статью всегда, независимо от списка допущенных. Остальные участники такую статью в списке не увидят — рядом с приватными статьями в базе знаний стоит иконка замка.</p>', 18),
('Что такое журнал активности?', '<p>Журнал активности — раздел в панели администратора, где фиксируются значимые действия команды: создание и изменение задач, идей и статей, смена статусов, приглашение участников, изменение прав доступа и т.д.</p>
<p>Записи можно отфильтровать по участнику и по дате. Журнал хранит записи только за последние 7 дней — более старые записи удаляются автоматически. Доступен только администраторам.</p>', 19),
('Как посмотреть статистику участника команды?', '<p>Администратор может открыть карточку участника в панели администратора и посмотреть его статистику за выбранный период: сколько задач он создал, сколько закрыл (довёл до архива с исходом «Реализовано»), сколько задач ему назначили как исполнителю, и сколько времени он провёл в приложении.</p>
<p>Обычным участникам своя статистика в личном кабинете пока не показывается — эта информация доступна только администратору.</p>', 20);
